import base64, hmac, hashlib

def b64url_nopad(b):
    return base64.urlsafe_b64encode(b).rstrip(b'=')

def sig_for(secret, value):
    # derive key using HMAC-SHA1 over salt with secret as key
    salt = b'cookie-session'
    derived = hmac.new(secret.encode(), salt, hashlib.sha1).digest()
    return b64url_nopad(hmac.new(derived, value, hashlib.sha1).digest())

